rejectionReasons.description:
This field only appears when the status of the process is 'rejected'. Contains the reasons given by the agent to have rejected the identification.<br>The available values are:<pre>{
  "type" : "Environment.CaptchaNotRead",
  "message" : "It is not evident that the person has read the captcha **captcha** in the video",
},
{
  "type" : "Environment.NotAppropriate",
  "message" : "There is no evidence of a living person, recognizable in a well-lit environment",
},
{
  "type" : "Document.Aspect",
  "message" : "There is no evidence of a legal identity document",
},
{
  "type" : "Document.NotSecurityElements",
  "message" : "Document security features are not identified",
},
{
  "type" : "Document.NotLegible",
  "message" : "Document data is not legible",
},
{
  "type" : "Document.DoesNotMatchData",
  "message" : "The front side of the document does not match with the back side",
},
{
  "type" : "Photo.Invalid",
  "message" : "The characteristics of the photo are not identified with those determined in the protocol",
},
{
  "type" : "Photo.DoesNotMatchPerson",
  "message" : "The person in the video does not match with the photo in the document",
},
{
  "type" : "Custom.Question",
  "message" : "Custom question to be filled out by the agent",
},
{
  "type" : "Document.Expired",
	"message" : "Expired Document",
},
{
  "type" : "Person.Underage",
  "message" : "The person is a minor",
}
</pre>
